export { AnimatedBeam } from "./AnimatedBeam";
export type { AnimatedBeamProps } from "./AnimatedBeam";
export { BeveledNode } from "./BeveledNode";
export type { BeveledNodeProps } from "./BeveledNode";
export { BeveledBeamShowcase } from "./BeveledBeamShowcase";
export type { BeveledBeamShowcaseProps, ShowcaseItem } from "./BeveledBeamShowcase";

"use client";

import React, { RefObject, useEffect, useId, useState } from "react";
import { motion } from "framer-motion";
import { cn } from "../../lib/utils";

export interface AnimatedBeamProps {
  className?: string;
  containerRef: RefObject<HTMLElement | null>;
  fromRef: RefObject<HTMLElement | null>;
  toRef: RefObject<HTMLElement | null>;
  curvature?: number;
  reverse?: boolean;
  pathColor?: string;
  pathWidth?: number;
  pathOpacity?: number;
  gradientStartColor?: string;
  gradientStopColor?: string;
  delay?: number;
  duration?: number;
  repeat?: number;
  repeatDelay?: number;
  startXOffset?: number;
  startYOffset?: number;
  endXOffset?: number;
  endYOffset?: number;
}

export const AnimatedBeam: React.FC<AnimatedBeamProps> = ({
  className,
  containerRef,
  fromRef,
  toRef,
  curvature = 0,
  reverse = false,
  duration = 3.5,
  delay = 0,
  pathColor = "rgba(255, 255, 255, 0.08)",
  pathWidth = 1.5,
  pathOpacity = 0.5,
  gradientStartColor = "#3b82f6",
  gradientStopColor = "#8b5cf6",
  repeat = Infinity,
  repeatDelay = 0,
  startXOffset = 0,
  startYOffset = 0,
  endXOffset = 0,
  endYOffset = 0,
}) => {
  const id = useId().replace(/:/g, "");
  const [pathD, setPathD] = useState("");
  const [svgDimensions, setSvgDimensions] = useState({ width: 0, height: 0 });

  const gradientCoordinates = reverse
    ? {
        x1: ["90%", "-10%"],
        x2: ["100%", "0%"],
        y1: ["0%", "0%"],
        y2: ["0%", "0%"],
      }
    : {
        x1: ["10%", "110%"],
        x2: ["0%", "100%"],
        y1: ["0%", "0%"],
        y2: ["0%", "0%"],
      };

  useEffect(() => {
    const updatePath = () => {
      if (containerRef.current && fromRef.current && toRef.current) {
        const containerRect = containerRef.current.getBoundingClientRect();
        const rectA = fromRef.current.getBoundingClientRect();
        const rectB = toRef.current.getBoundingClientRect();

        const svgWidth = containerRect.width;
        const svgHeight = containerRect.height;
        setSvgDimensions({ width: svgWidth, height: svgHeight });

        const startX =
          rectA.left - containerRect.left + rectA.width / 2 + startXOffset;
        const startY =
          rectA.top - containerRect.top + rectA.height / 2 + startYOffset;
        const endX =
          rectB.left - containerRect.left + rectB.width / 2 + endXOffset;
        const endY =
          rectB.top - containerRect.top + rectB.height / 2 + endYOffset;

        const controlY = startY - curvature;
        const d = `M ${startX},${startY} Q ${(startX + endX) / 2},${controlY} ${endX},${endY}`;
        setPathD(d);
      }
    };

    const resizeObserver = new ResizeObserver(() => {
      updatePath();
    });

    if (containerRef.current) {
      resizeObserver.observe(containerRef.current);
    }

    updatePath();

    return () => {
      resizeObserver.disconnect();
    };
  }, [
    containerRef,
    fromRef,
    toRef,
    curvature,
    startXOffset,
    startYOffset,
    endXOffset,
    endYOffset,
  ]);

  return (
    <svg
      fill="none"
      width={svgDimensions.width}
      height={svgDimensions.height}
      xmlns="http://www.w3.org/2000/svg"
      className={cn(
        "pointer-events-none absolute top-0 left-0 transform-gpu",
        className
      )}
      viewBox={`0 0 ${svgDimensions.width} ${svgDimensions.height}`}
    >
      <path
        d={pathD}
        stroke={pathColor}
        strokeWidth={pathWidth}
        strokeOpacity={pathOpacity}
        strokeLinecap="round"
      />
      <path
        d={pathD}
        strokeWidth={pathWidth}
        stroke={`url(#${id})`}
        strokeOpacity="1"
        strokeLinecap="round"
      />
      <defs>
        <motion.linearGradient
          className="transform-gpu"
          id={id}
          gradientUnits="userSpaceOnUse"
          initial={{
            x1: "0%",
            x2: "0%",
            y1: "0%",
            y2: "0%",
          }}
          animate={{
            x1: gradientCoordinates.x1,
            x2: gradientCoordinates.x2,
            y1: gradientCoordinates.y1,
            y2: gradientCoordinates.y2,
          }}
          transition={{
            delay,
            duration,
            ease: [0.16, 1, 0.3, 1], // easeOutExpo
            repeat,
            repeatDelay,
          }}
        >
          <stop stopColor={gradientStartColor} stopOpacity="0" />
          <stop stopColor={gradientStartColor} />
          <stop offset="32.5%" stopColor={gradientStopColor} />
          <stop offset="100%" stopColor={gradientStopColor} stopOpacity="0" />
        </motion.linearGradient>
      </defs>
    </svg>
  );
};

"use client";

import React, { forwardRef } from "react";
import { cn } from "../../lib/utils";

export interface BeveledNodeProps extends React.HTMLAttributes<HTMLDivElement> {
  shape?: "circle" | "square" | "rounded";
  size?: number;
  glowColor?: string;
  glowOpacity?: number;
  monochrome?: boolean;
}

export const BeveledNode = forwardRef<HTMLDivElement, BeveledNodeProps>(
  ({ className, shape = "circle", size = 52, glowColor, glowOpacity = 0.15, monochrome = false, children, ...props }, ref) => {
    const shapeClasses = {
      circle: "rounded-full",
      square: "rounded-none",
      rounded: "rounded-xl",
    };

    const hasGlow = !!glowColor && !monochrome;

    return (
      <div
        ref={ref}
        className={cn(
          "relative flex items-center justify-center shrink-0 border border-white/5 bg-[#070707] transition-all duration-300",
          shapeClasses[shape],
          className
        )}
        style={{
          width: `${size}px`,
          height: `${size}px`,
          boxShadow: hasGlow
            ? `inset 0 1.5px 3.5px rgba(0,0,0,0.8), 0 0 12px ${glowColor}${Math.round(glowOpacity * 255).toString(16).padStart(2, '0')}`
            : monochrome
              ? "inset 0 1.5px 3.5px rgba(0,0,0,0.9), inset 0 0 0 1px rgba(255,255,255,0.02)"
              : "inset 0 1.5px 3.5px rgba(0,0,0,0.8)",
        }}
        {...props}
      >
        <div className={cn("flex items-center justify-center transition-all duration-300", monochrome && "filter grayscale opacity-90 contrast-200 text-white [&_svg]:!text-white [&_svg]:!stroke-white")}>
          {children}
        </div>
      </div>
    );
  }
);

BeveledNode.displayName = "BeveledNode";

"use client";

import React, { useRef } from "react";
import { BeveledNode } from "./BeveledNode";
import { AnimatedBeam } from "./AnimatedBeam";
import { cn } from "../../lib/utils";

export interface ShowcaseItem {
  id: string;
  icon: React.ReactNode;
  shape?: "circle" | "square" | "rounded";
  beamStartColor?: string;
  beamStopColor?: string;
  curvature?: number;
  reverse?: boolean;
}

export interface BeveledBeamShowcaseProps {
  className?: string;
  variant?: "default" | "monochrome" | "neon";
  centerIcon?: React.ReactNode;
  centerShape?: "circle" | "square" | "rounded";
  leftItems?: ShowcaseItem[];
  rightItems?: ShowcaseItem[];
  pathColor?: string;
  pathWidth?: number;
  pathOpacity?: number;
  duration?: number;
}

export function BeveledBeamShowcase({
  className,
  variant = "default",
  centerIcon,
  centerShape = "circle",
  leftItems = [],
  rightItems = [],
  pathColor,
  pathWidth = 1.5,
  pathOpacity,
  duration = 3.5,
}: BeveledBeamShowcaseProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const centerRef = useRef<HTMLDivElement>(null);

  // Allocate arrays of refs for left/right nodes dynamically
  const leftRefs = useRef<Record<string, HTMLDivElement | null>>({});
  const rightRefs = useRef<Record<string, HTMLDivElement | null>>({});

  // Resolve theme overrides
  const isMonochrome = variant === "monochrome";
  const isNeon = variant === "neon";

  const resolvedPathColor = pathColor 
    ? pathColor 
    : isMonochrome 
      ? "rgba(255, 255, 255, 0.04)" 
      : isNeon 
        ? "rgba(0, 240, 255, 0.06)" 
        : "rgba(255, 255, 255, 0.08)";

  const resolvedPathOpacity = pathOpacity !== undefined
    ? pathOpacity 
    : isMonochrome 
      ? 0.3 
      : 0.5;

  return (
    <div
      ref={containerRef}
      className={cn(
        "relative flex w-full max-w-2xl items-center justify-between p-10 bg-transparent overflow-hidden",
        className
      )}
    >
      {/* Left Column Items */}
      <div className="flex flex-col justify-between gap-10 z-10">
        {leftItems.map((item) => {
          let glowColor = item.beamStartColor;
          if (isMonochrome) glowColor = undefined;
          if (isNeon) glowColor = "#ff007f"; // Neon Hot Pink
          return (
            <BeveledNode
              key={item.id}
              shape={item.shape || "circle"}
              ref={(el) => {
                leftRefs.current[item.id] = el;
              }}
              glowColor={glowColor}
              glowOpacity={isMonochrome ? 0 : 0.2}
              monochrome={isMonochrome}
            >
              {item.icon}
            </BeveledNode>
          );
        })}
      </div>

      {/* Central Hub Node */}
      <div className="flex items-center justify-center z-10">
        <BeveledNode
          shape={centerShape}
          ref={centerRef}
          size={72}
          glowColor={isMonochrome ? undefined : isNeon ? "#00f0ff" : "#ffffff"}
          glowOpacity={isMonochrome ? 0 : isNeon ? 0.25 : 0.05}
          monochrome={isMonochrome}
        >
          {centerIcon}
        </BeveledNode>
      </div>

      {/* Right Column Items */}
      <div className="flex flex-col justify-between gap-10 z-10">
        {rightItems.map((item) => {
          let glowColor = item.beamStopColor;
          if (isMonochrome) glowColor = undefined;
          if (isNeon) glowColor = "#00f0ff"; // Neon Cyan
          return (
            <BeveledNode
              key={item.id}
              shape={item.shape || "circle"}
              ref={(el) => {
                rightRefs.current[item.id] = el;
              }}
              glowColor={glowColor}
              glowOpacity={isMonochrome ? 0 : 0.2}
              monochrome={isMonochrome}
            >
              {item.icon}
            </BeveledNode>
          );
        })}
      </div>

      {/* Render Beams dynamically */}
      {leftItems.map((item) => {
        const itemRef = { current: leftRefs.current[item.id] };

        let startColor = item.beamStartColor ?? "#3b82f6";
        let stopColor = item.beamStopColor ?? "#8b5cf6";
        if (isMonochrome) {
          startColor = "#525252";
          stopColor = "#18181b";
        } else if (isNeon) {
          startColor = "#ff007f";
          stopColor = "#00f0ff";
        }

        return (
          <AnimatedBeam
            key={`beam-left-${item.id}`}
            containerRef={containerRef}
            fromRef={itemRef}
            toRef={centerRef}
            curvature={item.curvature ?? 20}
            reverse={item.reverse ?? false}
            pathColor={resolvedPathColor}
            pathWidth={pathWidth}
            pathOpacity={resolvedPathOpacity}
            gradientStartColor={startColor}
            gradientStopColor={stopColor}
            duration={duration}
          />
        );
      })}

      {rightItems.map((item) => {
        const itemRef = { current: rightRefs.current[item.id] };

        let startColor = item.beamStartColor ?? "#8b5cf6";
        let stopColor = item.beamStopColor ?? "#3b82f6";
        if (isMonochrome) {
          startColor = "#18181b";
          stopColor = "#525252";
        } else if (isNeon) {
          startColor = "#ff007f";
          stopColor = "#00f0ff";
        }

        return (
          <AnimatedBeam
            key={`beam-right-${item.id}`}
            containerRef={containerRef}
            fromRef={centerRef}
            toRef={itemRef}
            curvature={item.curvature ?? -20}
            reverse={item.reverse ?? false}
            pathColor={resolvedPathColor}
            pathWidth={pathWidth}
            pathOpacity={resolvedPathOpacity}
            gradientStartColor={startColor}
            gradientStopColor={stopColor}
            duration={duration}
          />
        );
      })}
    </div>
  );
}
